"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[4101],{44139:e=>{e.exports=JSON.parse('{"functions":[{"name":"Destroy","desc":"Cleans up all connections and resources used by the character controller.","params":[],"returns":[],"function_type":"method","source":{"line":138,"path":"src/Client/Classes/CharacterController/init.luau"}},{"name":"IsA","desc":"Returns whether the character controller is of the given [CharacterType].","params":[{"name":"characterType","desc":"","lua_type":"CharacterType"}],"returns":[{"desc":"","lua_type":"boolean"}],"function_type":"method","source":{"line":149,"path":"src/Client/Classes/CharacterController/init.luau"}},{"name":"_init","desc":"Initializes the character controller with the given character [Model], constructing the local [TiltCharacter].","params":[{"name":"instance","desc":"","lua_type":"Model"}],"returns":[],"function_type":"method","private":true,"source":{"line":160,"path":"src/Client/Classes/CharacterController/init.luau"}},{"name":"_onDied","desc":"Handles character death, marking the character controller as dead and destroying it.","params":[],"returns":[],"function_type":"method","private":true,"source":{"line":189,"path":"src/Client/Classes/CharacterController/init.luau"}},{"name":"_onPostSimulation","desc":"Processes post-simulation updates, such as updating the tilt angle of the character.","params":[{"name":"deltaTime","desc":"","lua_type":"number"}],"returns":[],"function_type":"method","private":true,"source":{"line":201,"path":"src/Client/Classes/CharacterController/init.luau"}}],"properties":[{"name":"Instance","desc":"The character [Model] controlled by the character controller.","lua_type":"Model","source":{"line":54,"path":"src/Client/Classes/CharacterController/init.luau"}},{"name":"_characterType","desc":"The [CharacterType] of the character controller.","lua_type":"CharacterType","private":true,"source":{"line":61,"path":"src/Client/Classes/CharacterController/init.luau"}},{"name":"_trove","desc":"The [Trove] used to manage the character controller\'s connections and resources.","lua_type":"Trove","private":true,"source":{"line":67,"path":"src/Client/Classes/CharacterController/init.luau"}},{"name":"_isAlive","desc":"Whether the character is alive.","lua_type":"boolean","private":true,"source":{"line":73,"path":"src/Client/Classes/CharacterController/init.luau"}},{"name":"_tiltAccumulator","desc":"The time accumulator for updating the tilt angle of the character.","lua_type":"number","private":true,"source":{"line":79,"path":"src/Client/Classes/CharacterController/init.luau"}},{"name":"_tiltSendRate","desc":"The rate at which the tilt angle of the character is sent to the server.","lua_type":"number","private":true,"source":{"line":85,"path":"src/Client/Classes/CharacterController/init.luau"}},{"name":"_prevTiltAngle","desc":"The previous tilt angle of the character.","lua_type":"number","private":true,"source":{"line":91,"path":"src/Client/Classes/CharacterController/init.luau"}},{"name":"_tiltCharacter","desc":"The [TiltCharacter] instance used to update the tilt angle of the character.","lua_type":"TiltCharacter","private":true,"source":{"line":97,"path":"src/Client/Classes/CharacterController/init.luau"}}],"types":[],"name":"CharacterController","desc":"CharacterController is an abstract base class designed to manage the behavior and state of a player-controlled character in the game. \\nIt provides foundational functionality such as tilt angle management, resource cleanup, and integration with Roblox services. \\nAs an abstract class, it cannot be instantiated directly but must be extended by subclasses that define specific character behaviors \\nand additional features.\\n\\n### Core Features:\\n- **Tilt Management**: Tracks and updates the tilt angle of the character based on the camera\'s look vector and communicates \\n  these changes to the server for replication.\\n- **Lifecycle Events**: Responds to key character lifecycle events, such as death, and handles associated cleanup operations.\\n- **Simulation Updates**: Executes logic during the [RunService.PostSimulation] event to ensure consistent updates tied to the game loop.\\n- **Resource Management**: Utilizes the [Trove] library to manage connections and ensure proper cleanup of resources.\\n\\n### Server Interaction:\\n- The tilt updates are sent to the server via the `Tilt` [RemoteEvent], which is handled by the [RoundPlayerHandler].\\n- The [RoundPlayerHandler] ensures that the tilt updates are replicated to other clients, allowing them to see the character\'s \\n  updated tilt in real-time.\\n\\n### Usage:\\nBy extending this class, developers can focus on implementing custom behaviors while leveraging the built-in infrastructure \\nfor robust character management. Subclasses are expected to override and expand upon the methods and properties provided by \\nthe base class to suit specific gameplay mechanics.","tags":["Abstract"],"realm":["Client"],"source":{"line":125,"path":"src/Client/Classes/CharacterController/init.luau"}}')}}]);